(function () {
	//loading js
	var runScript = (function(){
		"use strict";
		var doc = document,
			head = doc.getElementsByTagName("head")[0],
			isIE = navigator.userAgent.match(/MSIE (\d+(?:\.\d+)?)/),
			versionOfIE = isIE && +isIE[1],
			lessThanIE9 = (isIE = !!isIE) && (versionOfIE < 9 || "documentMode" in doc && doc.documentMode < 9)
		return function(options, complete){
			if (typeof options == "string") {
				options = {
					url: options,
					data: {},
					oncomplete: complete
				};
			}
			var url = options.url,
				data = options.data,
				charset = options.charset || "gbk",
				oncomplete = complete || options.oncomplete,
				ontimeout = options.ontimeout,
				timeout = "timeout" in options ? options.timeout : 3e4,
				tHandle,
				script = doc.createElement("script");


			if (options.data.callback) {
				window[options.data.callback] = oncomplete;
			}
			if (data) {
				for (var key in data) {
					url += (/\?/.test(url) ? "&" : "?") + key + "=" + encodeURIComponent(data[key]);
				}
			}
			var script = script = doc.createElement("script");
			script.type = "text/javascript";
			script.charset = charset;
			script.src = url;
			// incompatible for ie 6 [78]?
			if (lessThanIE9) {
				script.onreadystatechange = function() {
					if (/loaded|complete/i.test(script.readyState)) {
						try {
							clearTimeout(tHandle);
							script.onreadystatechange = null;
							head.removeChild(script);
						} catch(e) {}
						if (!options.data.callback) {
							oncomplete && oncomplete();
						}
					}
				};
			} else {
				script.onload = function() {
					try {
						clearTimeout(tHandle);
						script.onload = null;
						head.removeChild(script);
					} catch(e) {}
					if (!options.data.callback) {
						oncomplete && oncomplete();
					}
				};
			}
			if (ontimeout) {
				// load js timeout
				tHandle = setTimeout(function(){
					try {
						head.removeChild(script);
					} catch (e) {}
					ontimeout();
				}, timeout);
			}
			head.appendChild(script);
		};
	})();
	// 
	function getCookie(name, value, expires) {
		if (typeof value != 'undefined') {
			var expires = !value ? -1 : expires;
			if (typeof expires == 'number') {
				var date = new Date();
				date.setTime(date.getTime() + (expires * 60 * 1000));
				expires = '; expires=' + date.toUTCString();
			} else {
				expires = '';
			}
			var _domain = location.host.indexOf('.500.com') != -1 ? '500.com' : '500boss.com';
			document.cookie = [name, '=', encodeURIComponent(value), expires, '; path=/', '; domain='+_domain].join('');
		} else {
			var m = ''; 
			if (m = new RegExp("(^|)" + name + "=([^;]*)(;|$)", "gi").exec(document.cookie)) {
				return decodeURIComponent(m[2]);
			}
			return null;
		}
	}

	//main domain
	var sDomain = '.'+ location.host.split('.').slice(-2, -1).toString() + '.com'
	//get login info url
	var sAjaxGetLoginInfoUrl = '//passport' + sDomain + '/login/ajaxGetLoginInfo.php';
	//sync dg login url
	var sDgLoginUrl = '//wx' + sDomain + '/port/dglogin.php';

	function commonAjaxGetLoginInfo (callback, params) {
		params = params || {}
		params['ltype'] = 'js';
		runScript({
			url: sAjaxGetLoginInfoUrl, 
			data:params, 
			oncomplete: function () {
				var data = window.passportuserinfo;
				if (data == -1 || data == -2) {
					return callback && callback(data)
				}
				var enkey = data[15] || ''
				if (enkey) {
					//sync dg login
					var params1 = {isajax: '1', callback: 'dgLoginCallback', enkey: enkey};
					var bCheckCallback = false;
					runScript({
						url: sDgLoginUrl, 
						data: params1, 
						oncomplete: function (json) {
							if (bCheckCallback) {
								return;
							}
							bCheckCallback = true;
							callback && callback(data[0]);
						}
					});
					setTimeout(function(){
						if (bCheckCallback){
							return;
						}
						bCheckCallback = true;
						callback && callback(data[0]);
					}, 3000);
					return;
				}
				callback && callback(data[0]);
			}
		});
	}

	var iTryTime = 0;
	var iTryMaxTimes = 1;
	//auto login
	function autoLogin(callback){
		var username = getCookie('ck_user_utf8');
		var ck_expire = getCookie('ck_expire');

		var currenttime = Math.round(new Date() / 1000);
		if (ck_expire &&  currenttime + 120 > ck_expire) {
			if (iTryTime >= iTryMaxTimes) {
				return;
			}
			iTryTime++;
			commonAjaxGetLoginInfo(function (data) {
				if(data && data == -2){//鑷姩鐧诲綍骞跺彂杩斿洖
					setTimeout(function (){
						autoLogin(callback);
					},3000);  
					return;
				}
				callback && callback(username);
			});
		}
		return callback && callback(username);
	}
	window.commonAjaxGetLoginInfo = commonAjaxGetLoginInfo;
	window.commonAutoLogin = autoLogin;
})();

